import React, { useState, useEffect } from 'react'; // Ensure React is imported
import { Link } from 'react-router-dom';

const VendorManage = () => {
  const [vendors, setVendors] = useState([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [filteredEvents, setFilteredEvents] = useState([]);

  useEffect(() => {
    const fetchVendors = async () => {
      const response = await fetch('http://localhost:8000/vendor/get');
      const data = await response.json();
      setVendors(data);
    };
    fetchVendors();
  }, []);

  const handleSearchInputChange = (e) => {
    setSearchQuery(e.target.value);
  };

  const handleSearch = async () => {
    const response = await fetch(`http://localhost:8000/event/search?event_name=${searchQuery}`);
    const data = await response.json();
    setFilteredEvents(data);
  };

  return (
    <div>
      <input
        type="text"
        placeholder="Search events"
        value={searchQuery}
        onChange={handleSearchInputChange}
      />
      <button onClick={handleSearch}>Search</button>
      {/* Display filtered events */}
      {filteredEvents.map((event) => (
        <div key={event.event_id}>
          <Link to={`/event/${event.event_id}`}>{event.event_name}</Link>
        </div>
      ))}
      {/* Existing code to display vendors */}
      <Link to="/vendor/register">Register New Vendor</Link>
      {vendors.map((vendor) => (
        <div key={vendor.vendor_id}>
          {vendor.vendor_name} <Link to={`/vendor/edit/${vendor.vendor_id}`}>Edit</Link>
        </div>
      ))}
    </div>
  );
};

export default VendorManage;
